external_knowledge:
- Storm clouds: Metaphor for types of alarms; 
- Ships: Metaphor for units such as Fire Trucks, Ambulances, or Police Vehicles; 
- Gathering fleets: Refers to the count of units associated with each alarm type.

sql:
SELECT alm_type_name, description 
FROM alarm_types
WHERE alm_type_trigger = 'Fire';

SELECT DISTINCT iua.unit_id, ipa.personnel_id
FROM incident_unit_assignments iua
INNER JOIN incident_personnel_assignments ipa ON iua.inci_id = ipa.inci_id;

SELECT inci_id, COUNT(personnel_id) AS personnel_count
FROM incident_personnel_assignments
GROUP BY inci_id;

SELECT s.station_name, s.station_type, p.personnel_name 
FROM stations s 
LEFT JOIN personnel p ON s.station_id = p.personnel_station_id;

SELECT station_name, station_capacity
FROM stations
ORDER BY station_capacity DESC;

SELECT personnel_name 
FROM personnel 
WHERE personnel_station_id = 100;

SELECT station_id, station_name, station_type
FROM stations
ORDER BY station_name ASC;

